import{f as l,D as i,o as a,c as o,a2 as d,b as n,w as e,a as s,G as h,a5 as D}from"./chunks/framework.Ccw_j35p.js";const P=JSON.parse('{"title":"DNS 解析","description":"","frontmatter":{},"headers":[],"relativePath":"computer-network/application/dns.md","filePath":"computer-network/application/dns.md","lastUpdated":1780924599000}'),E={name:"computer-network/application/dns.md"};function S(p,t,N,A,c,b){const r=i("Mermaid");return a(),o("div",null,[t[1]||(t[1]=d('<h1 id="dns-解析" tabindex="-1">DNS 解析 <a class="header-anchor" href="#dns-解析" aria-label="Permalink to &quot;DNS 解析&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>考察点</th><th>重要程度</th><th>面试频率</th><th>掌握目标</th></tr></thead><tbody><tr><td>完整 DNS 解析流程</td><td>⭐⭐⭐</td><td>极高</td><td>能完整说一遍从浏览器缓存到根服务器</td></tr><tr><td>递归查询 vs 迭代查询</td><td>⭐⭐⭐</td><td>极高</td><td>理解区别，谁对谁用递归</td></tr><tr><td>DNS 缓存</td><td>⭐⭐⭐</td><td>高</td><td>缓存层级、TTL 作用</td></tr><tr><td>DNS 负载均衡</td><td>⭐⭐</td><td>高</td><td>原理和优缺点</td></tr><tr><td>DNS 污染与劫持</td><td>⭐⭐⭐</td><td>极高</td><td>定义、差异、防护方式</td></tr><tr><td>HTTPDNS</td><td>⭐⭐⭐</td><td>高</td><td>解决了什么问题、原理</td></tr></tbody></table><hr><h2 id="一、dns-是什么" tabindex="-1">一、DNS 是什么 <a class="header-anchor" href="#一、dns-是什么" aria-label="Permalink to &quot;一、DNS 是什么&quot;">​</a></h2><p>DNS（Domain Name System，域名系统）的作用是<strong>域名 → IP 地址的映射</strong>。人类记住域名比一串 IP 容易多了，但网络传输需要 IP 地址找到服务器。</p><p>DNS 可以看作互联网的&quot;电话簿&quot;：你给域名，它返回对应的 IP。</p><div class="tip custom-block"><p class="custom-block-title">DNS 默认端口</p><p>DNS 使用 UDP 协议，端口 53。DNS 区域传送和大报文使用 TCP 协议，端口也是 53。</p></div><hr><h2 id="二、完整-dns-解析流程" tabindex="-1">二、完整 DNS 解析流程 <a class="header-anchor" href="#二、完整-dns-解析流程" aria-label="Permalink to &quot;二、完整 DNS 解析流程&quot;">​</a></h2><p>从浏览器输入域名到得到 IP，DNS 解析会查询多级缓存和服务器：</p>',11)),(a(),n(D,null,{default:e(()=>[h(r,{id:"mermaid-132",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20B%20as%20%E6%B5%8F%E8%A7%88%E5%99%A8%0A%20%20%20%20participant%20OS%20as%20%E6%93%8D%E4%BD%9C%E7%B3%BB%E7%BB%9F%0A%20%20%20%20participant%20LD%20as%20%E6%9C%AC%E5%9C%B0%20DNS%20%E6%9C%8D%E5%8A%A1%E5%99%A8%20(ISP%20DNS)%0A%20%20%20%20participant%20R%20as%20%E6%A0%B9%20DNS%20%E6%9C%8D%E5%8A%A1%E5%99%A8%0A%20%20%20%20participant%20TLD%20as%20%E9%A1%B6%E7%BA%A7%E5%9F%9F%20DNS%20%E6%9C%8D%E5%8A%A1%E5%99%A8%20(.com)%0A%20%20%20%20participant%20A%20as%20%E6%9D%83%E5%A8%81%20DNS%20%E6%9C%8D%E5%8A%A1%E5%99%A8%20(example.com)%0A%20%20%20%20B-%3E%3EB%3A%20%E6%A3%80%E6%9F%A5%E6%B5%8F%E8%A7%88%E5%99%A8%E7%BC%93%E5%AD%98%0A%20%20%20%20alt%20%E5%91%BD%E4%B8%AD%0A%20%20%20%20%20%20%20%20B-%3E%3EB%3A%20%E8%BF%94%E5%9B%9E%E7%BC%93%E5%AD%98%20IP%0A%20%20%20%20else%20%E6%9C%AA%E5%91%BD%E4%B8%AD%0A%20%20%20%20%20%20%20%20B-%3E%3EOS%3A%20%E6%9F%A5%E8%AF%A2%E7%B3%BB%E7%BB%9F%20hosts%20%2F%20%E6%93%8D%E4%BD%9C%E7%B3%BB%E7%BB%9F%E7%BC%93%E5%AD%98%0A%20%20%20%20%20%20%20%20alt%20%E5%91%BD%E4%B8%AD%0A%20%20%20%20%20%20%20%20%20%20%20%20OS-%3E%3EB%3A%20%E8%BF%94%E5%9B%9E%20IP%0A%20%20%20%20%20%20%20%20else%20%E6%9C%AA%E5%91%BD%E4%B8%AD%0A%20%20%20%20%20%20%20%20%20%20%20%20OS-%3E%3ELD%3A%20%E6%9C%AC%E5%9C%B0%20DNS%20%E9%80%92%E5%BD%92%E6%9F%A5%E8%AF%A2%0A%20%20%20%20%20%20%20%20%20%20%20%20LD-%3E%3ELD%3A%20%E6%A3%80%E6%9F%A5%E6%9C%AC%E5%9C%B0%E7%BC%93%E5%AD%98%0A%20%20%20%20%20%20%20%20%20%20%20%20alt%20%E5%91%BD%E4%B8%AD%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20LD-%3E%3EOS%3A%20%E8%BF%94%E5%9B%9E%20IP%0A%20%20%20%20%20%20%20%20%20%20%20%20else%20%E6%9C%AA%E5%91%BD%E4%B8%AD%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20LD-%3E%3ER%3A%20%E8%AF%B7%E6%B1%82%E6%A0%B9%E6%9C%8D%E5%8A%A1%E5%99%A8%E8%BF%AD%E4%BB%A3%E6%9F%A5%E8%AF%A2%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20R-%3E%3ELD%3A%20%E8%BF%94%E5%9B%9E%20.com%20%E9%A1%B6%E7%BA%A7%E5%9F%9F%E6%9C%8D%E5%8A%A1%E5%99%A8%E5%9C%B0%E5%9D%80%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20LD-%3E%3ETLD%3A%20%E8%AF%B7%E6%B1%82%E9%A1%B6%E7%BA%A7%E5%9F%9F%E6%9C%8D%E5%8A%A1%E5%99%A8%E8%BF%AD%E4%BB%A3%E6%9F%A5%E8%AF%A2%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20TLD-%3E%3ELD%3A%20%E8%BF%94%E5%9B%9E%20example.com%20%E6%9D%83%E5%A8%81%E6%9C%8D%E5%8A%A1%E5%99%A8%E5%9C%B0%E5%9D%80%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20LD-%3E%3EA%3A%20%E8%AF%B7%E6%B1%82%20example.com%20%E6%9D%83%E5%A8%81%E6%9C%8D%E5%8A%A1%E5%99%A8%E8%BF%AD%E4%BB%A3%E6%9F%A5%E8%AF%A2%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20A-%3E%3ELD%3A%20%E8%BF%94%E5%9B%9E%20example.com%20%E5%AF%B9%E5%BA%94%E7%9A%84%20IP%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20LD-%3E%3EOS%3A%20%E8%BF%94%E5%9B%9E%20IP%EF%BC%8CLD%20%E7%BC%93%E5%AD%98%E7%BB%93%E6%9E%9C%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20OS-%3E%3EB%3A%20%E8%BF%94%E5%9B%9E%20IP%EF%BC%8COS%20%E7%BC%93%E5%AD%98%E7%BB%93%E6%9E%9C%0A%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20B-%3E%3EB%3A%20%E6%B5%8F%E8%A7%88%E5%99%A8%E7%BC%93%E5%AD%98%E7%BB%93%E6%9E%9C%0A%20%20%20%20%20%20%20%20%20%20%20%20end%0A%20%20%20%20%20%20%20%20end%0A%20%20%20%20end%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=d(`<p>完整流程一步步拆解：</p><h3 id="_1-浏览器缓存" tabindex="-1">1. 浏览器缓存 <a class="header-anchor" href="#_1-浏览器缓存" aria-label="Permalink to &quot;1. 浏览器缓存&quot;">​</a></h3><p>浏览器首先检查自己的缓存：</p><ul><li>缓存时间由 TTL 控制（Time To Live）</li><li>过期的 DNS 记录会被清除</li><li>每个浏览器对缓存大小都有限制</li></ul><h3 id="_2-操作系统缓存" tabindex="-1">2. 操作系统缓存 <a class="header-anchor" href="#_2-操作系统缓存" aria-label="Permalink to &quot;2. 操作系统缓存&quot;">​</a></h3><p>浏览器缓存找不到，向操作系统查询：</p><ul><li>操作系统会维护 DNS 缓存</li><li>检查 <code>hosts</code> 文件（Windows 在 <code>C:\\Windows\\System32\\drivers\\etc\\hosts</code>，Linux 在 <code>/etc/hosts</code>）</li><li>hosts 文件中配置的域名-IP 映射会优先使用</li></ul><h3 id="_3-本地-dns-服务器-ldns" tabindex="-1">3. 本地 DNS 服务器（LDNS） <a class="header-anchor" href="#_3-本地-dns-服务器-ldns" aria-label="Permalink to &quot;3. 本地 DNS 服务器（LDNS）&quot;">​</a></h3><p>操作系统缓存找不到，查询 LDNS。LDNS 一般由运营商提供（电信 DNS、联通 DNS），或者公共 DNS（114.114.114.114、8.8.8.8）。</p><p>LDNS 也会检查缓存：</p><ul><li>如果缓存命中，直接返回 IP</li><li>如果不命中，开始递归查询</li></ul><h3 id="_4-根域名服务器查询" tabindex="-1">4. 根域名服务器查询 <a class="header-anchor" href="#_4-根域名服务器查询" aria-label="Permalink to &quot;4. 根域名服务器查询&quot;">​</a></h3><p>根域名服务器是 DNS 体系的最顶层，全球 13 组根服务器。根服务器不知道具体域名对应哪个 IP，只知道顶级域服务器的地址。</p><p>根服务器返回对应的顶级域（.com/.cn）服务器地址。</p><h3 id="_5-顶级域服务器查询" tabindex="-1">5. 顶级域服务器查询 <a class="header-anchor" href="#_5-顶级域服务器查询" aria-label="Permalink to &quot;5. 顶级域服务器查询&quot;">​</a></h3><p>顶级域服务器知道该域名对应的权威 DNS 服务器地址，返回给 LDNS。</p><h3 id="_6-权威-dns-服务器查询" tabindex="-1">6. 权威 DNS 服务器查询 <a class="header-anchor" href="#_6-权威-dns-服务器查询" aria-label="Permalink to &quot;6. 权威 DNS 服务器查询&quot;">​</a></h3><p>权威 DNS 服务器是域名实际管理者维护的 DNS 服务器，存储了该域名的具体记录，直接返回域名对应的 IP。</p><h3 id="_7-缓存结果" tabindex="-1">7. 缓存结果 <a class="header-anchor" href="#_7-缓存结果" aria-label="Permalink to &quot;7. 缓存结果&quot;">​</a></h3><p>LDNS 收到 IP 后，缓存结果，然后返回给操作系统，操作系统缓存结果，再返回给浏览器，浏览器缓存结果。最终，整个查询完成。</p><hr><h2 id="三、递归查询-vs-迭代查询" tabindex="-1">三、递归查询 vs 迭代查询 <a class="header-anchor" href="#三、递归查询-vs-迭代查询" aria-label="Permalink to &quot;三、递归查询 vs 迭代查询&quot;">​</a></h2><p>这是面试中非常高频的考点，必须分清楚区别。</p><h3 id="定义对比" tabindex="-1">定义对比 <a class="header-anchor" href="#定义对比" aria-label="Permalink to &quot;定义对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>查询类型</th><th>定义</th><th>责任方</th></tr></thead><tbody><tr><td>递归查询</td><td>如果被查询者不知道答案，就代替请求者向其他服务器查询，最终返回答案给请求者</td><td>被查询者负责拿答案</td></tr><tr><td>迭代查询</td><td>如果被查询者不知道答案，只返回下一级服务器地址，请求者自己去问下一级</td><td>请求者自己负责继续问</td></tr></tbody></table><h3 id="实际查询过程中谁用什么" tabindex="-1">实际查询过程中谁用什么 <a class="header-anchor" href="#实际查询过程中谁用什么" aria-label="Permalink to &quot;实际查询过程中谁用什么&quot;">​</a></h3><ul><li><strong>客户端 → LDNS：递归查询</strong> → LDNS 负责拿答案，最后直接给我们返回 IP</li><li><strong>LDNS → 根、顶级、权威：迭代查询</strong> → LDNS 依次问各级服务器，每级只返回下一级地址，LDNS 自己继续问，直到拿到答案</li></ul><div class="tip custom-block"><p class="custom-block-title">面试口诀</p><p>递归：你不知道就帮我问别人，把结果给我。迭代：我不知道，我告诉你谁知道，你自己去问他。</p></div><hr><h2 id="四、dns-缓存" tabindex="-1">四、DNS 缓存 <a class="header-anchor" href="#四、dns-缓存" aria-label="Permalink to &quot;四、DNS 缓存&quot;">​</a></h2><p>DNS 缓存分为多个层级，每一级都缓存，目的是减少 DNS 查询次数，提高解析速度。</p><table tabindex="0"><thead><tr><th>缓存层级</th><th>位置</th><th>作用</th></tr></thead><tbody><tr><td>浏览器缓存</td><td>浏览器进程</td><td>最快，命中直接返回</td></tr><tr><td>操作系统缓存</td><td>OS 内核</td><td>hosts 文件也在这里</td></tr><tr><td>本地 DNS 缓存</td><td>ISP LDNS</td><td>大部分域名在这里命中</td></tr><tr><td>各级 DNS 服务器缓存</td><td>根/顶级/权威服务器</td><td>减少重复查询</td></tr></tbody></table><h3 id="ttl-time-to-live" tabindex="-1">TTL（Time To Live） <a class="header-anchor" href="#ttl-time-to-live" aria-label="Permalink to &quot;TTL（Time To Live）&quot;">​</a></h3><p>TTL 就是缓存的过期时间，单位秒：</p><ul><li>TTL 越小，缓存时间越短，更新越快，但查询次数越多</li><li>TTL 越大，缓存命中率越高，但更新慢，切换 IP 时生效慢</li><li>做域名切换时，一般先调小 TTL，切换完成后再调大</li></ul><hr><h2 id="五、dns-负载均衡" tabindex="-1">五、DNS 负载均衡 <a class="header-anchor" href="#五、dns-负载均衡" aria-label="Permalink to &quot;五、DNS 负载均衡&quot;">​</a></h2><p>很多大型网站一台服务器扛不住，有多台服务器。同一个域名对应多个 IP，DNS 可以通过轮询把请求分散到不同服务器上，这就是 DNS 负载均衡。</p><h3 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>example.com.  IN  A  1.1.1.1</span></span>
<span class="line"><span>example.com.  IN  A  2.2.2.2</span></span>
<span class="line"><span>example.com.  IN  A  3.3.3.3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>DNS 服务器配置多个 A 记录，每次查询轮询返回不同 IP，不同用户会被分配到不同服务器，实现负载均衡。</p><h3 id="优缺点" tabindex="-1">优缺点 <a class="header-anchor" href="#优缺点" aria-label="Permalink to &quot;优缺点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>简单，不需要自己做负载均衡</td><td>不能感知后端节点健康（节点挂了 DNS 还会返回）</td></tr><tr><td>DNS 就近解析，可以把用户分配到离用户最近的机房</td><td>DNS 缓存会导致负载不均衡</td></tr><tr><td>降低了自建负载均衡的压力</td><td>粒度粗，只能做轮询，不能根据权重分配</td></tr></tbody></table><h3 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h3><p>DNS 负载均衡通常作为第一层负载均衡，实际应用中一般是：DNS → LVS → Nginx → 应用服务器。参见高并发模块的负载均衡章节。</p><hr><h2 id="六、dns-污染-vs-dns-劫持" tabindex="-1">六、DNS 污染 vs DNS 劫持 <a class="header-anchor" href="#六、dns-污染-vs-dns-劫持" aria-label="Permalink to &quot;六、DNS 污染 vs DNS 劫持&quot;">​</a></h2><p>这两个概念面试中经常被混淆，要分清楚区别。</p><h3 id="dns-污染-dns-poisoning" tabindex="-1">DNS 污染（DNS Poisoning） <a class="header-anchor" href="#dns-污染-dns-poisoning" aria-label="Permalink to &quot;DNS 污染（DNS Poisoning）&quot;">​</a></h3><p>DNS 污染是指攻击者篡改了 DNS 记录，把正确域名映射到错误 IP。通常发生在递归查询过程中，攻击者伪造 DNS 响应，让解析结果错误。</p><h3 id="dns-劫持" tabindex="-1">DNS 劫持 <a class="header-anchor" href="#dns-劫持" aria-label="Permalink to &quot;DNS 劫持&quot;">​</a></h3><p>DNS 劫持是运营商或第三方把 DNS 查询结果劫持，重定向到自己的服务器。常见场景：运营商劫持，把不存在的域名解析到广告页面。</p><h3 id="区别" tabindex="-1">区别 <a class="header-anchor" href="#区别" aria-label="Permalink to &quot;区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th>DNS 污染</th><th>DNS 劫持</th></tr></thead><tbody><tr><td>篡改 DNS 响应内容</td><td>拦截 DNS 查询请求</td></tr><tr><td>攻击者不知道你的请求，提前把错误记录发过来</td><td>拦截请求，返回错误 IP</td></tr><tr><td>一般用于阻止访问特定域名</td><td>一般用于插入广告、流量劫持</td></tr></tbody></table><h3 id="防护方式" tabindex="-1">防护方式 <a class="header-anchor" href="#防护方式" aria-label="Permalink to &quot;防护方式&quot;">​</a></h3><ul><li>使用 HTTPS 加密站点，会被浏览器提示证书错误，用户就能发现问题</li><li>使用加密 DNS：DNS over TLS (DoT)、DNS over HTTPS (DoH)</li><li>使用 HTTPDNS（移动端常用），走 HTTP 请求获取解析结果</li></ul><hr><h2 id="七、httpdns" tabindex="-1">七、HTTPDNS <a class="header-anchor" href="#七、httpdns" aria-label="Permalink to &quot;七、HTTPDNS&quot;">​</a></h2><p>HTTPDNS 是通过 HTTP 请求获取 DNS 解析结果，绕过传统 LDNS。现在各大互联网公司移动端都在使用。</p><h3 id="传统-dns-有什么问题" tabindex="-1">传统 DNS 有什么问题？ <a class="header-anchor" href="#传统-dns-有什么问题" aria-label="Permalink to &quot;传统 DNS 有什么问题？&quot;">​</a></h3><ol><li><strong>DNS 劫持</strong>：运营商篡改解析结果，跳转到广告页面</li><li><strong>DNS 污染</strong>：返回错误 IP</li><li><strong>解析不准确</strong>：LDNS 缓存导致分配不到就近的 IP，影响用户访问速度</li><li><strong>更新慢</strong>：TTL 过期才能更新，域名切换慢</li><li><strong>UDP 传输</strong>：可能丢包，重试会增加延迟</li></ol><h3 id="httpdns-原理" tabindex="-1">HTTPDNS 原理 <a class="header-anchor" href="#httpdns-原理" aria-label="Permalink to &quot;HTTPDNS 原理&quot;">​</a></h3><p>客户端不向 LDNS 发起 DNS 查询，而是向 HTTPDNS 服务端（通常是云厂商或公司自建）发起 HTTP 请求，请求域名解析，HTTPDNS 直接返回 IP 给客户端。</p><h3 id="httpdns-优缺点" tabindex="-1">HTTPDNS 优缺点 <a class="header-anchor" href="#httpdns-优缺点" aria-label="Permalink to &quot;HTTPDNS 优缺点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>绕过 LDNS，有效防止劫持和污染</td><td>每次查询都要走 HTTP 请求，有一定开销</td></tr><tr><td>可以根据客户端 IP 精确调度就近节点，提高速度</td><td>需要客户端配合实现</td></tr><tr><td>解析结果可控，更新快</td><td>占用 HTTP 连接</td></tr></tbody></table><p>HTTPDNS 现在是移动端解决 DNS 问题的主流方案。</p><div class="tip custom-block"><p class="custom-block-title">相关链接</p><p>HTTPDNS 在移动互联网广泛使用，解决了运营商 DNS 劫持和解析不准的问题，相关技术参见 <a href="./../optimization/cdn">CDN 加速</a> 中的动态调度。</p></div><hr><h2 id="八、dns-常见记录类型" tabindex="-1">八、DNS 常见记录类型 <a class="header-anchor" href="#八、dns-常见记录类型" aria-label="Permalink to &quot;八、DNS 常见记录类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>记录类型</th><th>作用</th></tr></thead><tbody><tr><td>A</td><td>域名 → IPv4 地址</td></tr><tr><td>AAAA</td><td>域名 → IPv6 地址</td></tr><tr><td>CNAME</td><td>域名 → 另一个域名（别名）</td></tr><tr><td>MX</td><td>邮件交换，指定邮件服务器</td></tr><tr><td>NS</td><td>权威域名服务器，指定由哪个 DNS 服务器负责该域名</td></tr><tr><td>TXT</td><td>任意文本记录，常用于域名验证（如 SPF、DKIM）</td></tr><tr><td>PTR</td><td>IP 反向解析 → 域名</td></tr></tbody></table><hr><h2 id="九、交叉关联到其他模块" tabindex="-1">九、交叉关联到其他模块 <a class="header-anchor" href="#九、交叉关联到其他模块" aria-label="Permalink to &quot;九、交叉关联到其他模块&quot;">​</a></h2><ul><li><strong>UDP 协议</strong>：参见 <a href="./../fundamentals/udp">UDP 协议</a>，DNS 默认使用 UDP</li><li><strong>CDN 加速</strong>：参见 <a href="./../optimization/cdn">CDN 加速</a>，CDN 依赖 DNS 就近解析</li><li><strong>负载均衡</strong>：DNS 是第一层负载均衡，参见高并发架构负载均衡章节</li><li><strong>HTTPS 证书</strong>：参见 <a href="./https-tls">HTTPS 与 TLS</a>，域名验证需要 DNS 配置 TXT 记录</li></ul><hr><h2 id="十、经典高频面试题" tabindex="-1">十、经典高频面试题 <a class="header-anchor" href="#十、经典高频面试题" aria-label="Permalink to &quot;十、经典高频面试题&quot;">​</a></h2><h3 id="q1-从输入-url-到得到-ip-完整的-dns-解析过程是怎样的" tabindex="-1">Q1：从输入 URL 到得到 IP，完整的 DNS 解析过程是怎样的？ <a class="header-anchor" href="#q1-从输入-url-到得到-ip-完整的-dns-解析过程是怎样的" aria-label="Permalink to &quot;Q1：从输入 URL 到得到 IP，完整的 DNS 解析过程是怎样的？&quot;">​</a></h3><p><strong>参考答案：</strong></p><ol><li>浏览器检查自身缓存，命中则直接返回 IP</li><li>浏览器缓存未命中，查询操作系统缓存和 hosts 文件，命中返回 IP</li><li>操作系统缓存未命中，向本地 DNS 服务器（LDNS）发起递归查询</li><li>LDNS 检查自身缓存，命中返回 IP</li><li>LDNS 缓存未命中，从根域名服务器开始迭代查询： <ul><li>根服务器返回顶级域服务器地址</li><li>LDNS 查询顶级域服务器，得到权威服务器地址</li><li>LDNS 查询权威服务器，得到域名对应的 IP</li></ul></li><li>LDNS 缓存结果，返回给操作系统，操作系统缓存</li><li>操作系统返回给浏览器，浏览器缓存结果</li></ol><p>整个过程一次递归查询（客户端 → LDNS），多级迭代查询（LDNS → 根 → 顶级 → 权威）。</p><h3 id="q2-递归查询和迭代查询的区别是什么" tabindex="-1">Q2：递归查询和迭代查询的区别是什么？ <a class="header-anchor" href="#q2-递归查询和迭代查询的区别是什么" aria-label="Permalink to &quot;Q2：递归查询和迭代查询的区别是什么？&quot;">​</a></h3><p><strong>参考答案：</strong></p><table tabindex="0"><thead><tr><th>区别</th><th>递归查询</th><th>迭代查询</th></tr></thead><tbody><tr><td>定义</td><td>被查询者不知道答案就帮查询者去问，最后直接返回结果</td><td>被查询者不知道答案只返回下一级地址，查询者自己去问</td></tr><tr><td>谁辛苦</td><td>被查询者辛苦，请求者轻松</td><td>请求者辛苦，被查询者轻松</td></tr><tr><td>实际使用</td><td>客户端 → LDNS 一般用递归</td><td>LDNS 查询各级 DNS 服务器用迭代</td></tr></tbody></table><p>口诀：递归：你帮我拿到答案给我。迭代：我不知道，我告诉你谁知道，你自己找他要。</p><h3 id="q3-什么是-dns-缓存-ttl-有什么作用" tabindex="-1">Q3：什么是 DNS 缓存？TTL 有什么作用？ <a class="header-anchor" href="#q3-什么是-dns-缓存-ttl-有什么作用" aria-label="Permalink to &quot;Q3：什么是 DNS 缓存？TTL 有什么作用？&quot;">​</a></h3><p><strong>参考答案：</strong> DNS 缓存是各级 DNS 服务器（浏览器缓存、操作系统缓存、LDNS、各级权威服务器）都会缓存 DNS 解析结果，减少重复查询，提高解析速度。</p><p>TTL（Time To Live）是缓存的过期时间，单位秒：</p><ul><li>TTL 越小：缓存更新快，但缓存命中率低，查询次数多</li><li>TTL 越大：缓存命中率高，但更新慢，域名切换时生效慢</li></ul><p>做域名切换时，一般会先把 TTL 调小，等待旧缓存过期后切换，切换完成再调大 TTL 提高命中率。</p><h3 id="q4-dns-污染和-dns-劫持有什么区别" tabindex="-1">Q4：DNS 污染和 DNS 劫持有什么区别？ <a class="header-anchor" href="#q4-dns-污染和-dns-劫持有什么区别" aria-label="Permalink to &quot;Q4：DNS 污染和 DNS 劫持有什么区别？&quot;">​</a></h3><p><strong>参考答案：</strong></p><ul><li><strong>DNS 污染</strong>：攻击者伪造 DNS 响应，把正确域名解析成错误 IP。一般发生在查询过程中，攻击者抢先发送伪造响应。通常用于阻止访问特定域名。</li><li><strong>DNS 劫持</strong>：运营商或第三方拦截 DNS 查询请求，不按照 DNS 协议返回正确结果，而是把请求重定向到广告页面，或者返回错误 IP。通常用于插入广告、收集用户流量。</li></ul><p>防护方式：使用加密 DNS（DoT/DoH）、HTTPDNS 绕过传统 LDNS。</p><h3 id="q5-什么是-httpdns-解决了什么问题" tabindex="-1">Q5：什么是 HTTPDNS？解决了什么问题？ <a class="header-anchor" href="#q5-什么是-httpdns-解决了什么问题" aria-label="Permalink to &quot;Q5：什么是 HTTPDNS？解决了什么问题？&quot;">​</a></h3><p><strong>参考答案：</strong> HTTPDNS 是通过 HTTP 请求向 HTTPDNS 服务端查询域名解析结果，绕过传统本地 DNS 服务器。</p><p>解决了传统 DNS 的问题：</p><ol><li><p><strong>DNS 劫持</strong>：运营商劫持返回错误 IP，插入广告</p></li><li><p><strong>DNS 污染</strong>：返回错误解析结果</p></li><li><p><strong>调度不准确</strong>：传统 DNS 基于 LDNS 所在位置，不能按真实客户端 IP 就近调度</p></li><li><p><strong>更新慢</strong>：TTL 导致域名切换生效慢，HTTPDNS 缓存可以实时更新</p></li></ol><p>原理：客户端直接向 HTTPDNS 服务端发起 HTTP 请求，获取域名对应的 IP，不需要走传统 DNS 查询。</p><h3 id="q6-dns-负载均衡是什么-优缺点是什么" tabindex="-1">Q6：DNS 负载均衡是什么？优缺点是什么？ <a class="header-anchor" href="#q6-dns-负载均衡是什么-优缺点是什么" aria-label="Permalink to &quot;Q6：DNS 负载均衡是什么？优缺点是什么？&quot;">​</a></h3><p><strong>参考答案：</strong> DNS 负载均衡：同一个域名配置多个 A 记录，对应多个服务器 IP，DNS 查询时轮询返回不同 IP，把请求分散到不同服务器。</p><p>优点：</p><ol><li>实现简单，不需要额外改造</li><li>可以基于地理位置就近调度</li><li>降低上游负载均衡的压力</li></ol><p>缺点：</p><ol><li>不能感知后端节点健康状态，节点下线后 DNS 还会返回 IP</li><li>DNS 缓存导致负载不均衡，某些节点可能接收更多流量</li><li>调度粒度粗，不支持根据后端负载动态调整</li></ol><p>实际大型架构中，DNS 负载均衡通常作为第一层，后面再接 LVS/HaProxy/Nginx 做多层负载均衡。</p>`,104))])}const T=l(E,[["render",S]]);export{P as __pageData,T as default};
